---
interface Link {
	href: string;
	text: string;
}

const links: Link[] = [
	{ href: '/', text: 'HN' },
	{ href: '/new', text: 'New' },
	{ href: '/show', text: 'Show' },
	{ href: '/ask', text: 'Ask' },
	{ href: '/job', text: 'Jobs' },
];
---

<header>
	<nav aria-label="Main menu">
		{
			links.map(({ href, text }) => (
				<a href={href} aria-current={href === Astro.url.pathname ? 'page' : undefined}>
					<strong>{text}</strong>
				</a>
			))
		}
		<a class="github" href="http://github.com/withastro/astro" target="_blank" rel="noreferrer">
			Built with Astro
		</a>
	</nav>
</header>

<style>
	header {
		background-color: rgb(107 33 168);
		position: fixed;
		z-index: 999;
		height: 55px;
		top: 0;
		left: 0;
		right: 0;
	}

	nav {
		max-width: 800px;
		box-sizing: border-box;
		margin: 0 auto;
		padding: 15px 5px;
	}

	nav a {
		color: rgba(248, 250, 252, 0.8);
		line-height: 24px;
		transition: color 0.15s ease;
		display: inline-block;
		vertical-align: middle;
		font-weight: 300;
		letter-spacing: 0.075em;
		margin-right: 1.8em;
	}

	nav a:hover {
		color: rgb(248 250 252);
	}

	nav [aria-current='page'] {
		color: rgb(248 250 252);
		font-weight: 400;
	}

	nav a:last-of-type {
		margin-right: 0;
	}

	.github {
		color: rgb(248 250 252);
		font-size: 0.9em;
		margin: 0;
		float: right;
	}

	@media (max-width: 860px) {
		nav {
			padding: 15px 30px;
		}
	}

	@media (max-width: 600px) {
		nav {
			padding: 15px;
		}

		a {
			margin-right: 1em;
		}

		.github {
			display: none;
		}
	}
</style>

---
import Show from '../../components/Show.astro';
import Layout from '../../layouts/Layout.astro';
import fetchAPI from '../../lib/api';
import type { IUser } from '../../types.js';

const { id } = Astro.params as { id: string };

const user = (await fetchAPI(`user/${id}`)) as IUser;
---

<Layout>
	<main>
		<Show when={user}>
			<Show when={!user.error}>
				<h1 slot="fallback">User not found.</h1>
				<h1>User : {user.id}</h1>
				<ul class="meta">
					<li>
						<span class="label">Created:</span>
						{user.created}
					</li>
					<li>
						<span class="label">Karma:</span>
						{user.karma}
					</li>
					<Show when={user.about}>
						<li set:html={user.about} class="about" />{' '}
					</Show>
				</ul>
				<p>
					<a href={`https://news.ycombinator.com/submitted?id=${user.id}`}>submissions</a> |{' '}
					<a href={`https://news.ycombinator.com/threads?id=${user.id}`}>comments</a>
				</p>
			</Show>
		</Show>
	</main>
</Layout>

<style>
	main {
		background-color: rgb(248 250 252);
		box-sizing: border-box;
		padding: 2em 3em;
	}

	h1 {
		margin: 0;
		font-size: 1.5em;
	}

	.meta {
		list-style-type: none;
		padding: 0;
	}

	.label {
		display: inline-block;
		min-width: 4em;
	}

	.about {
		margin: 1em 0;
	}

	p a {
		text-decoration: underline;
	}
</style>

---
interface Props {
	title: string;
}

const { title } = Astro.props;
---

<html lang="en">
	<head>
		<meta charset="utf-8" />
		<meta name="viewport" content="width=device-width, initial-scale=1" />
		<title>{title}</title>
	</head>
	<body>
		<header>
			<a href="/" class="logo">acme</a>
			<nav>
				<a href="/">Home</a>
				<a href="/dashboard">Dashboard</a>
				<a href="/login">Login</a>
				<a href="/es">ES</a>
			</nav>
		</header>
		<main>
			<slot />
		</main>
	</body>
</html>

<style>
	:global(*) {
		margin: 0;
		padding: 0;
		box-sizing: border-box;
	}

	:global(body) {
		font-family:
			system-ui,
			-apple-system,
			sans-serif;
		background: #0f1117;
		color: #e1e4ed;
		min-height: 100vh;
	}

	header {
		border-bottom: 1px solid #2a2d3a;
		padding: 1rem 2rem;
		display: flex;
		align-items: center;
		justify-content: space-between;
	}

	.logo {
		font-weight: 700;
		font-size: 1.125rem;
		color: #6366f1;
		text-decoration: none;
	}

	nav {
		display: flex;
		gap: 1.5rem;
	}

	nav a {
		color: #8b8fa3;
		text-decoration: none;
		font-size: 0.875rem;
		transition: color 0.15s;
	}

	nav a:hover {
		color: #e1e4ed;
	}

	main {
		max-width: 48rem;
		margin: 0 auto;
		padding: 3rem 2rem;
	}
</style>

---
import Layout from '../layouts/Layout.astro';
---

<Layout title="Home">
	<h1>Advanced Routing</h1>
	<p>
		This example uses <code>src/app.ts</code> to control the request pipeline with Hono. Individual feature
		middleware from <code>astro/hono</code> and <code>astro/fetch</code>
		are composed together, with your own Hono middleware running between them.
	</p>

	<div class="cards">
		<a href="/dashboard" class="card">
			<h2>Dashboard</h2>
			<p>Protected by auth middleware. You'll be redirected to login without a session cookie.</p>
		</a>
		<a href="/old-dashboard" class="card">
			<h2>Old Dashboard Link</h2>
			<p>Redirected by Astro's built-in routing inside <code>astro()</code>.</p>
		</a>
		<a href="/es" class="card">
			<h2>Spanish</h2>
			<p>Served through Astro's i18n handling, also composed inside <code>astro()</code>.</p>
		</a>
	</div>
</Layout>

<style>
	h1 {
		font-size: 1.75rem;
		font-weight: 700;
		margin-bottom: 1rem;
		color: blue;
	}

	p {
		color: #8b8fa3;
		line-height: 1.6;
		margin-bottom: 1rem;
	}

	code {
		background: #1a1d27;
		border: 1px solid #2a2d3a;
		padding: 0.15em 0.4em;
		border-radius: 4px;
		font-size: 0.85em;
	}

	.cards {
		display: grid;
		gap: 1rem;
		margin-top: 1.5rem;
	}

	.card {
		display: block;
		background: #1a1d27;
		border: 1px solid #2a2d3a;
		border-radius: 8px;
		padding: 1.5rem;
		text-decoration: none;
		color: inherit;
		transition: border-color 0.15s;
	}

	.card:hover {
		border-color: #6366f1;
	}

	.card h2 {
		font-size: 1.125rem;
		font-weight: 600;
		margin-bottom: 0.5rem;
		color: #e1e4ed;
	}

	.card p {
		margin-bottom: 0;
		font-size: 0.875rem;
	}
</style>

