---
import Container from '../components/Container.astro';
import Header from '../components/Header.astro';
---

<html lang="en">
	<head>
		<title>Online Store</title>
		<style>
			h1 {
				font-size: 36px;
			}
		</style>

		<script type="module" is:inline>
			document.addEventListener('DOMContentLoaded', () => {
				const form = document.querySelector('form');
				if (!form) throw new Error('Form not found');
				form.addEventListener('submit', (e) => {
					e.preventDefault();
					const formData = new FormData(form);
					const data = Object.fromEntries(formData);

					fetch('/login.form.async', {
						method: 'POST',
						body: JSON.stringify(data),
					})
						.then((res) => res.json())
						.then(() => {
							const result = document.querySelector('#result');
							if (result) {
								result.innerHTML =
									'Progressive login was successful! you will be redirected to the store in 3 seconds';
								setTimeout(() => (location.href = '/'), 3000);
							}
						});
				});
			});
		</script>
	</head>
	<body>
		<Header />

		<Container tag="main">
			<h1>Login</h1>
			<form action="/login.form" method="POST">
				<label for="name">Name</label>
				<input type="text" name="name" />

				<label for="password">Password</label>
				<input type="password" name="password" />

				<input type="submit" value="Submit" />
			</form>
			<div id="result"></div>
		</Container>
	</body>
</html>

import { EnumChangefreq as ChangeFreq } from 'sitemap';
import * as z from 'zod/v4';
import { SITEMAP_CONFIG_DEFAULTS } from './config-defaults.js';

const localeKeySchema = z.string().min(1);

export const SitemapOptionsSchema = z
	.object({
		filenameBase: z.string().optional().prefault(SITEMAP_CONFIG_DEFAULTS.filenameBase),
		filter: z.function({ input: [z.string()], output: z.boolean() }).optional(),
		customSitemaps: z.array(z.url()).optional(),
		customPages: z.array(z.url()).optional(),
		canonicalURL: z.url().optional(),
		xslURL: z.string().optional(),

		i18n: z
			.object({
				defaultLocale: localeKeySchema,
				locales: z.record(
					localeKeySchema,
					z
						.string()
						.min(2)
						.regex(/^[a-zA-Z\-]+$/gm, {
							message: 'Only English alphabet symbols and hyphen allowed',
						}),
				),
			})
			.refine((val) => !val || val.locales[val.defaultLocale], {
				message: '`defaultLocale` must exist in `locales` keys',
			})
			.optional(),

		entryLimit: z.number().nonnegative().optional().default(SITEMAP_CONFIG_DEFAULTS.entryLimit),
		serialize: z.function({ input: [z.any()], output: z.any() }).optional(),

		changefreq: z.enum(ChangeFreq).optional(),
		lastmod: z.date().optional(),
		priority: z.number().min(0).max(1).optional(),

		namespaces: z
			.object({
				news: z.boolean().optional(),
				xhtml: z.boolean().optional(),
				image: z.boolean().optional(),
				video: z.boolean().optional(),
			})
			.optional()
			.default(SITEMAP_CONFIG_DEFAULTS.namespaces),
		chunks: z.record(z.string(), z.function({ input: [z.any()], output: z.any() })).optional(),
	})
	.strict()
	.default(SITEMAP_CONFIG_DEFAULTS);

---
import Icon from '../user-components/Icon.astro';

const { dir, pagination } = Astro.locals.starlightRoute;
const { prev, next } = pagination;
const isRtl = dir === 'rtl';
---

<div class="pagination-links print:hidden" dir={dir}>
	{
		prev && (
			<a href={prev.href} rel="prev">
				<Icon name={isRtl ? 'right-arrow' : 'left-arrow'} size="1.5rem" />
				<span>
					{Astro.locals.t('page.previousLink')}
					<br />
					<span class="link-title">{prev.label}</span>
				</span>
			</a>
		)
	}
	{
		next && (
			<a href={next.href} rel="next">
				<Icon name={isRtl ? 'left-arrow' : 'right-arrow'} size="1.5rem" />
				<span>
					{Astro.locals.t('page.nextLink')}
					<br />
					<span class="link-title">{next.label}</span>
				</span>
			</a>
		)
	}
</div>

<style>
	@layer starlight.core {
		.pagination-links {
			display: grid;
			grid-template-columns: repeat(auto-fit, minmax(min(18rem, 100%), 1fr));
			gap: 1rem;
		}

		a {
			display: flex;
			align-items: center;
			justify-content: flex-start;
			gap: 0.5rem;
			width: 100%;
			flex-basis: calc(50% - 0.5rem);
			flex-grow: 1;
			border: 1px solid var(--sl-color-gray-5);
			border-radius: 0.5rem;
			padding: 1rem;
			text-decoration: none;
			color: var(--sl-color-gray-2);
			box-shadow: var(--sl-shadow-md);
			overflow-wrap: anywhere;
		}
		[rel='next'] {
			justify-content: end;
			text-align: end;
			flex-direction: row-reverse;
		}
		a:hover {
			border-color: var(--sl-color-gray-2);
		}

		.link-title {
			color: var(--sl-color-white);
			font-size: var(--sl-text-2xl);
			line-height: var(--sl-line-height-headings);
		}

		svg {
			flex-shrink: 0;
		}
	}
</style>

---
import type { HTMLAttributes } from 'astro/types';
import Palette from './palette.astro';

interface Props extends HTMLAttributes<'div'> {
	labels: {
		lightMode: string;
		darkMode: string;
		bodyText: string;
		linkText: string;
		dimText: string;
		inlineCode: string;
	};
}
const { labels, ...attrs } = Astro.props;
const light = 'data-light' in attrs;
const linkColor = light ? '--sl-color-accent' : '--sl-color-accent-high';
const codeBg = light ? '--sl-color-gray-6' : '--sl-color-gray-5';
---

<div class="preview-card" {...attrs}>
	<h4>{light ? labels.lightMode : labels.darkMode}</h4>
	<p>
		{labels.bodyText}{' '}
		<span class="link" style={`color:var(${linkColor})`}>{labels.linkText}</span>{' '}
		<span class="dim">{labels.dimText}</span>{' '}
		<code style={`--sl-color-bg-inline-code:var(${codeBg})`}>{labels.inlineCode}</code>
	</p>
	<Palette {light} />
</div>

<style>
	.preview-card {
		margin: 0 !important;
		border: 1px solid var(--sl-color-gray-5);
		padding: 1rem;
		background-color: var(--sl-color-black);
	}

	p {
		margin-top: 0.5em !important;
		font-size: var(--sl-text-sm);
		color: var(--sl-color-gray-2);
	}

	.link {
		text-decoration: underline;
	}

	.dim {
		color: var(--sl-color-gray-3);
	}
</style>

---
import MobileTableOfContents from 'virtual:starlight/components/MobileTableOfContents';
import TableOfContents from 'virtual:starlight/components/TableOfContents';
---

{
	Astro.locals.starlightRoute.toc && (
		<>
			<div class="lg:sl-hidden">
				<MobileTableOfContents />
			</div>
			<div class="right-sidebar-panel sl-hidden lg:sl-block">
				<div class="sl-container">
					<TableOfContents />
				</div>
			</div>
		</>
	)
}

<style>
	@layer starlight.core {
		.right-sidebar-panel {
			padding: 1rem var(--sl-sidebar-pad-x);
		}
		.sl-container {
			width: calc(var(--sl-sidebar-width) - 2 * var(--sl-sidebar-pad-x));
		}
		.right-sidebar-panel :global(h2) {
			color: var(--sl-color-white);
			font-size: var(--sl-text-h5);
			font-weight: 600;
			line-height: var(--sl-line-height-headings);
			margin-bottom: 0.5rem;
		}
		.right-sidebar-panel :global(:where(a)) {
			display: block;
			font-size: var(--sl-text-xs);
			text-decoration: none;
			color: var(--sl-color-gray-3);
			overflow-wrap: anywhere;
		}
		.right-sidebar-panel :global(:where(a):hover) {
			color: var(--sl-color-white);
		}
		@media (min-width: 72rem) {
			.sl-container {
				max-width: calc(
					(
						(
								100vw - var(--sl-sidebar-width) - 2 * var(--sl-content-pad-x) - 2 *
									var(--sl-sidebar-pad-x)
							) * 0.25 /* MAGIC NUMBER 🥲 */
					)
				);
			}
		}
	}
</style>
